fn can_contain_in_circle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64), radius: f64) -> bool {
    if p1 == p2 && p2 == p3 {
        return true;
    }
    if p1 == p2 {
        let d = distance(p1, p3);
        return realcompare(d, 2.0 * radius) != "GT";
    }
    if p2 == p3 {
        let d = distance(p1, p2);
        return realcompare(d, 2.0 * radius) != "GT";
    }
    if p1 == p3 {
        let d = distance(p1, p2);
        return realcompare(d, 2.0 * radius) != "GT";
    }

    let (cx, cy) = circumcenter(p1, p2, p3);
    let r = distance((cx, cy), p1);

    if realcompare(r, radius) == "GT" {
        return false;
    }

    let d2 = distance((cx, cy), p2);
    let d3 = distance((cx, cy), p3);

    realcompare(d2, radius) != "GT" && realcompare(d3, radius) != "GT"
}

fn circumcenter(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> (f64, f64) {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;

    let d = 2.0 * (x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2));

    if d.abs() < 1e-12 {
        return ((x1 + x2 + x3) / 3.0, (y1 + y2 + y3) / 3.0);
    }

    let ux = ((x1 * x1 + y1 * y1) * (y2 - y3)
        + (x2 * x2 + y2 * y2) * (y3 - y1)
        + (x3 * x3 + y3 * y3) * (y1 - y2))
        / d;
    let uy = ((x1 * x1 + y1 * y1) * (x3 - x2)
        + (x2 * x2 + y2 * y2) * (x1 - x3)
        + (x3 * x3 + y3 * y3) * (x2 - x1))
        / d;

    (ux, uy)
}

fn distance(p1: (f64, f64), p2: (f64, f64)) -> f64 {
    let dx = p2.0 - p1.0;
    let dy = p2.1 - p1.1;
    (dx * dx + dy * dy).sqrt()
}

fn compute_angle(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let dx1 = p1.0 - p2.0;
    let dy1 = p1.1 - p2.1;
    let dx2 = p3.0 - p2.0;
    let dy2 = p3.1 - p2.1;

    let dot = dx1 * dx2 + dy1 * dy2;
    let mag1 = (dx1 * dx1 + dy1 * dy1).sqrt();
    let mag2 = (dx2 * dx2 + dy2 * dy2).sqrt();

    if mag1 < 1e-12 || mag2 < 1e-12 {
        return 0.0;
    }

    let cos_angle = dot / (mag1 * mag2);
    let cos_angle = cos_angle.max(-1.0).min(1.0);
    cos_angle.acos()
}

fn triangle_area(p1: (f64, f64), p2: (f64, f64), p3: (f64, f64)) -> f64 {
    let (x1, y1) = p1;
    let (x2, y2) = p2;
    let (x3, y3) = p3;

    ((x1 * (y2 - y3) + x2 * (y3 - y1) + x3 * (y1 - y2)).abs()) / 2.0
}

fn get_quadrant(x: f64, y: f64) -> i32 {
    if x >= 0.0 && y >= 0.0 {
        1
    } else if x < 0.0 && y >= 0.0 {
        2
    } else if x < 0.0 && y < 0.0 {
        3
    } else {
        4
    }
}

fn distance_to_line(p: (f64, f64), p1: (f64, f64), p2: (f64, f64)) -> f64 {
    if p1 == p2 {
        return distance(p, p1);
    }

    let (x0, y0) = p;
    let (x1, y1) = p1;
    let (x2, y2) = p2;

    let num = ((y2 - y1) * x0 - (x2 - x1) * y0 + x2 * y1 - y2 * x1).abs();
    let denom = ((y2 - y1).powi(2) + (x2 - x1).powi(2)).sqrt();

    num / denom
}

fn compute_pum(input: &DecideInput, cmv: &[bool]) -> Vec<Vec<bool>> {
    let mut pum = vec![vec![false; 15]; 15];

    for i in 0..15 {
        for j in 0..15 {
            if i == j {
                pum[i][j] = input.pum_diag[i];
            } else {
                let connector = &input.lcm[i][j];
                match connector.as_str() {
                    "NOTUSED" => pum[i][j] = true,
                    "ANDD" => pum[i][j] = cmv[i] && cmv[j],
                    "ORR" => pum[i][j] = cmv[i] || cmv[j],
                    _ => pum[i][j] = true,
                }
            }
        }
    }

    pum
}

fn compute_fuv(pum: &[Vec<bool>], pum_diag: &[bool]) -> Vec<bool> {
    let mut fuv = vec![false; 15];

    for i in 0..15 {
        if !pum_diag[i] {
            fuv[i] = true;
        } else {
            let all_true = pum[i].iter().all(|&v| v);
            fuv[i] = all_true;
        }
    }

    fuv
}
